ext_type_checking_complete.solution:
Theorem type_checking_complete : forall Gamma t T,
  Gamma |-- t \in T -> type_check Gamma t = Some T.
Proof.
  intros Gamma t T Hty.
  induction Hty; simpl;
    try reflexivity;
    try (rewrite IHHty; reflexivity);
    try (rewrite IHHty1; rewrite IHHty2; simpl;
         rewrite eqb_ty_refl; reflexivity);
    try (rewrite IHHty1; rewrite IHHty2; rewrite IHHty3; simpl;
         rewrite eqb_ty_refl; reflexivity).
  - (* var *) assumption.
Qed.

complete_stepf.solution:
Theorem complete_stepf : forall t t',
  t --> t' -> stepf t = Some t'.
Proof.
  intros t t' Hstep.
  induction Hstep; simpl;
    try (rewrite IHHstep; reflexivity);
    try (rewrite (complete_valuef _ H); reflexivity);
    try reflexivity.
Qed.
